#include <stdio.h>
#include <stdlib.h>
int main(){
    char buf[1024];
    size_t len = fread(buf,1,sizeof(buf)-1,stdin);
    buf[len]='\0';
    int T=1;
    char *p=buf;
    while(*p && (*p==' '||*p=='\n'||*p=='\r'||*p=='\t')) p++;
    if(*p && *p>='0' && *p<='9'){
        T=atoi(p);
        if(T<1) T=1;
    }
    const char *quote="\"Success is not final,\nFailure is not fatal: It is the courage to continue that counts.\"\n    - Winston Churchill";
    for(int i=0;i<T;i++){
        if(i) putchar('\n');
        fputs(quote,stdout);
    }
    return 0;
}

