import java.io.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sbAll=new StringBuilder();
        String line;
        while((line=br.readLine())!=null){
            sbAll.append(line).append('\n');
        }
        String all=sbAll.toString().trim();
        int T=1;
        if(!all.isEmpty()){
            try{
                int val=Integer.parseInt(all.split("\\s+")[0]);
                if(val>=1 && val<=100) T=val;
            }catch(NumberFormatException e){/*ignore*/}
        }
        String quote="\"Success is not final,\nFailure is not fatal: It is the courage to continue that counts.\"\n    - Winston Churchill";
        StringBuilder out=new StringBuilder();
        for(int i=0;i<T;i++){
            if(i>0) out.append('\n');
            out.append(quote);
        }
        System.out.print(out.toString());
    }
}

