import sys

def main():
    data=sys.stdin.read().strip().split()
    T=1
    if data:
        try:
            val=int(data[0])
            if 1<=val<=100:
                T=val
        except ValueError:
            pass
    quote='"Success is not final,\nFailure is not fatal: It is the courage to continue that counts."\n    - Winston Churchill'
    sys.stdout.write('\n'.join([quote]*T))

if __name__=='__main__':
    main()

